import { apiClient, unwrap } from '@linm-soft/common-components';
import type { BffResponse } from '@linm-soft/common-components';

const BASE = '/ccdc';

function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

async function getList<T>(path: string, params?: Record<string, string | number | boolean | undefined>): Promise<T[]> {
  const qs = params ? buildQs(params) : '';
  const res = await apiClient.get<BffResponse<T[]>>(`${path}${qs ? `?${qs}` : ''}`);
  return unwrap(res) ?? [];
}

export const ccdcEndpoint = {
  getInventory: (params?: Record<string, string | number | boolean | undefined>) =>
    getList<Record<string, unknown>>(`${BASE}/inventory`, params),

  getTransactions: (params?: Record<string, string | number | boolean | undefined>) =>
    getList<Record<string, unknown>>(`${BASE}/transactions`, params),

  createEntry: async (dto: object) => {
    const res = await apiClient.post<BffResponse<unknown>>(`${BASE}/transactions/entry`, dto);
    return unwrap(res);
  },

  createIssue: async (dto: object) => {
    const res = await apiClient.post<BffResponse<unknown>>(`${BASE}/transactions/issue`, dto);
    return unwrap(res);
  },

  getDisposals: (params?: Record<string, string | number | boolean | undefined>) =>
    getList<Record<string, unknown>>(`${BASE}/disposals`, params),
};

export const ccdcService = { ...ccdcEndpoint };
